local function CollectUseActions(self, doer, target, actions, right, ...) local finiteuses = target.components.finiteuses local current = finiteuses and finiteuses.current local total = finiteuses and finiteuses.total if right and target.components.repairable and target.components.repairable.repairmaterial == self.repairmaterial and self.userepairvalue and self.userepairvalue > 0x0 and current and total and current < total then table.insert(actions, ACTIONS.REPAIR) else if self.dycOldCollectUseActions then return self.dycOldCollectUseActions(self, doer, target, actions, right, ...) end end end local function DYCRepairer(self) self.dycOldCollectUseActions = self.CollectUseActions self.CollectUseActions = CollectUseActions self.userepairvalue = 0x0 end return DYCRepairer 